function solve(nums: number[]): number {
    const n = nums.length;
    const abs = nums.map(x => Math.abs(x));
    const coords = new Set<number>();
    for (const a of abs) {
        coords.add(a);
        coords.add(Math.ceil(a / 2));
        coords.add(2 * a);
    }
    const sortedCoords = Array.from(coords).sort((a, b) => a - b);
    const rankMap = new Map<number, number>();
    for (let i = 0; i < sortedCoords.length; i++) {
        rankMap.set(sortedCoords[i], i + 1);
    }
    const size = sortedCoords.length;
    const fenw = new BIT(size);
    let ans = 0;
    for (let j = 0; j < n; j++) {
        const a = abs[j];
        const L = Math.ceil(a / 2);
        const R = 2 * a;
        const l_rank = rankMap.get(L);
        const r_rank = rankMap.get(R);
        if (l_rank !== undefined && r_rank !== undefined) {
            ans += fenw.rangeQuery(l_rank, r_rank);
        }
        const a_rank = rankMap.get(a);
        if (a_rank !== undefined) {
            fenw.update(a_rank, 1);
        }
    }
    return ans;
}

class BIT {
    tree: number[];
    n: number;

    constructor(size: number) {
        this.n = size;
        this.tree = Array(this.n + 1).fill(0);
    }

    update(i: number, delta: number): void {
        while (i <= this.n) {
            this.tree[i] += delta;
            i += i & -i;
        }
    }

    query(i: number): number {
        let res = 0;
        while (i > 0) {
            res += this.tree[i];
            i -= i & -i;
        }
        return res;
    }

    rangeQuery(l: number, r: number): number {
        if (l > r) return 0;
        return this.query(r) - this.query(l - 1);
    }
}
